mapper.sql:


where 1 = 1



    and  tc.jurisdiction_setting = #{criteria.jurisdictionSetting,jdbcType=VARCHAR}



     and  (
       (tc.jurisdiction_setting = '公司全体人员可见' and (tc.approval_status = 'pass' or tc.approval_status is null))
     or tc.create_by = #{criteria.userId,jdbcType=BIGINT}
     or tc.dependent_id in (
      select distinct tpi.id from td_plan_implement tpi
       join td_plan_employee tpe on tpe.plan_implement_id = tpi.id and tpe.type = 'employee'
       where tpe.employee_id = #{criteria.employeeId,jdbcType=BIGINT}
     )
     or tc.id in (
         select distinct tce.courseware_id
         from td_courseware_employee tce
         where tce.employee_id = #{criteria.employeeId,jdbcType=BIGINT}
     )
     )






             and tls.create_time ${criteria.symbol} #{criteria.value,jdbcType=TIMESTAMP}




             and (tc.in_name ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}
               or tc.out_name ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR})




             and tc.${criteria.column} ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}

